15	const calculateQuotePremium = (items: any[]): number => {
16	  let basePremium = 0;
17	
18	  const componentCounts: Record<string, number> = {};
19	  for (const item of items) {
20	    if (isComponent(item)) {
21	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
22	    } else {
23	      basePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
24	    }
25	  }
26	
27	  for (const count of Object.values(componentCounts)) {
28	    if (count === BLOCK_SIZE) {
29	      basePremium += BLOCK_PREMIUM;
30	    } else {
31	      basePremium += count * COMPONENT_PREMIUM;
32	    }
33	  }
34	
35	  return basePremium + PROCESSING_FEE;
36	};
